import { useState, useContext } from 'react';
import { toast } from 'react-toastify';
import AuthContext from '../context/AuthContext';
import advisoryService from '../api/advisoryService';

function AdvisoryForm({ onAdvisoryCreated }) {
  const [formData, setFormData] = useState({
    soilType: '',
    season: '',
    waterLevel: '',
  });
  const [loading, setLoading] = useState(false);

  const { user } = useContext(AuthContext);
  const { soilType, season, waterLevel } = formData;

  const onChange = (e) => {
    setFormData((prevState) => ({
      ...prevState,
      [e.target.name]: e.target.value,
    }));
  };

  const onSubmit = async (e) => {
    e.preventDefault();

    if (!soilType || !season || !waterLevel) {
      toast.error('Please fill all fields');
      return;
    }

    try {
      setLoading(true);
      const advisory = await advisoryService.createAdvisory(formData, user.token);
      toast.success('Advisory created successfully');
      onAdvisoryCreated(advisory);
      setFormData({
        soilType: '',
        season: '',
        waterLevel: '',
      });
    } catch (error) {
      toast.error('Error creating advisory');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-md mb-8">
      <h2 className="text-2xl font-semibold text-green-700 mb-4">
        Get Crop Recommendations
      </h2>
      <form onSubmit={onSubmit}>
        <div className="form-group">
          <label className="block text-gray-700 mb-2" htmlFor="soilType">
            Soil Type
          </label>
          <select
            className="form-control"
            id="soilType"
            name="soilType"
            value={soilType}
            onChange={onChange}
            required
          >
            <option value="" disabled>
              Select soil type
            </option>
            <option value="clay">Clay Soil</option>
            <option value="sandy">Sandy Soil</option>
            <option value="loamy">Loamy Soil</option>
            <option value="black">Black Soil</option>
            <option value="red">Red Soil</option>
          </select>
        </div>

        <div className="form-group">
          <label className="block text-gray-700 mb-2" htmlFor="season">
            Season
          </label>
          <select
            className="form-control"
            id="season"
            name="season"
            value={season}
            onChange={onChange}
            required
          >
            <option value="" disabled>
              Select season
            </option>
            <option value="kharif">Kharif (Monsoon)</option>
            <option value="rabi">Rabi (Winter)</option>
            <option value="summer">Summer</option>
          </select>
        </div>

        <div className="form-group">
          <label className="block text-gray-700 mb-2" htmlFor="waterLevel">
            Water Availability
          </label>
          <select
            className="form-control"
            id="waterLevel"
            name="waterLevel"
            value={waterLevel}
            onChange={onChange}
            required
          >
            <option value="" disabled>
              Select water availability
            </option>
            <option value="high">High (Abundant irrigation)</option>
            <option value="medium">Medium (Limited irrigation)</option>
            <option value="low">Low (Mainly rainfed)</option>
          </select>
        </div>

        <button
          type="submit"
          className="btn btn-primary mt-4"
          disabled={loading}
        >
          {loading ? 'Getting Recommendations...' : 'Get Recommendations'}
        </button>
      </form>
    </div>
  );
}

export default AdvisoryForm;
